from __future__ import annotations

import html
import json
from pathlib import Path
from typing import Any, Dict, List


def generate_html_report(path: Path, campaign_slug: str, run_id: str, generated_at: str, input_config: Dict[str, Any], candidates: List[Dict[str, Any]], summary: Dict[str, Any]) -> None:
    """Generate a self-contained HTML report.

    The HTML embeds selected candidates for local viewing, while the source of truth
    remains data/selected-50.json.
    """
    path.parent.mkdir(parents=True, exist_ok=True)
    template = r'''<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>__PRODUCT__ Channel Discovery Report</title>
<style>
:root{--bg:#f5f7fb;--card:#fff;--text:#172033;--muted:#667085;--line:#e6eaf2;--blue:#2563eb;--blue2:#e8f0ff;--green:#138a45;--green2:#e9f7ef;--yellow:#a16207;--yellow2:#fff7df;--red:#b42318;--red2:#fff0ed;--shadow:0 10px 30px rgba(22,34,51,.07);--radius:18px}*{box-sizing:border-box}body{margin:0;font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:var(--bg);color:var(--text)}a{color:var(--blue);text-decoration:none}a:hover{text-decoration:underline}.page{max-width:1440px;margin:0 auto;padding:28px}.hero{display:grid;grid-template-columns:minmax(0,1.4fr) minmax(320px,.6fr);gap:20px}.card{background:var(--card);border:1px solid var(--line);border-radius:var(--radius);box-shadow:var(--shadow)}.hero-main{padding:28px;position:relative;overflow:hidden}.kicker{color:var(--blue);font-weight:800;letter-spacing:.04em;text-transform:uppercase;font-size:12px}h1{margin:10px 0 8px;font-size:clamp(28px,4vw,42px);line-height:1.08}.subtitle{color:var(--muted);font-size:15px;line-height:1.6;max-width:780px}.meta-list{display:grid;gap:12px;padding:22px}.meta-row{display:flex;justify-content:space-between;gap:12px;border-bottom:1px solid var(--line);padding-bottom:10px}.meta-row:last-child{border-bottom:0;padding-bottom:0}.meta-label{color:var(--muted);font-size:13px}.meta-value{font-weight:800;text-align:right}.stats{display:grid;grid-template-columns:repeat(7,minmax(140px,1fr));gap:14px;margin:18px 0}.stat{padding:18px}.stat-value{font-size:28px;font-weight:900}.stat-label{color:var(--muted);font-size:13px;margin-top:4px}.section{margin-top:22px}.section-header{display:flex;align-items:end;justify-content:space-between;gap:16px;margin-bottom:12px}.section-title{font-size:20px;font-weight:900}.section-subtitle{color:var(--muted);font-size:13px;margin-top:4px}.chips{display:flex;flex-wrap:wrap;gap:8px}.chip{display:inline-flex;align-items:center;padding:6px 10px;border-radius:999px;background:var(--blue2);color:#1d4ed8;font-size:12px;font-weight:800}.chip.warn{background:var(--yellow2);color:var(--yellow)}.chip.fail{background:var(--red2);color:var(--red)}.chip.ok{background:var(--green2);color:var(--green)}.top-grid{display:grid;grid-template-columns:repeat(5,minmax(220px,1fr));gap:14px}.top-card{padding:16px;display:flex;flex-direction:column;gap:10px}.top-card h3{margin:0;font-size:15px;line-height:1.35}.score-pill{display:inline-flex;align-items:center;justify-content:center;width:fit-content;min-width:60px;padding:6px 10px;border-radius:999px;font-weight:900;background:var(--blue2);color:var(--blue)}.priority,.review{display:inline-flex;width:fit-content;align-items:center;border-radius:999px;padding:5px 9px;font-size:12px;font-weight:900}.priority.High{background:var(--green2);color:var(--green)}.priority.Medium{background:var(--yellow2);color:var(--yellow)}.priority.Low{background:var(--red2);color:var(--red)}.review{background:#eef2ff;color:#3730a3}.small{font-size:12px;color:var(--muted);line-height:1.45}.warning-list{display:grid;gap:8px;padding:16px 18px}.warning-item{color:#7c2d12;background:#fff7ed;border:1px solid #fed7aa;border-radius:12px;padding:10px 12px;font-size:13px}.toolbar{display:grid;grid-template-columns:1.6fr repeat(5,minmax(140px,.6fr));gap:10px;padding:14px}input,select,button{width:100%;border:1px solid var(--line);border-radius:12px;padding:11px 12px;background:#fff;color:var(--text);font:inherit}button{cursor:pointer;background:var(--blue);color:#fff;border-color:var(--blue);font-weight:800}.toggle-row{display:flex;gap:14px;align-items:center;padding:0 14px 14px;color:var(--muted);font-size:13px}.toggle-row label{display:inline-flex;align-items:center;gap:8px}.toggle-row input{width:auto}.table-wrap{overflow:auto;border-top:1px solid var(--line)}table{width:100%;border-collapse:collapse;font-size:13px;min-width:1360px}th{position:sticky;top:0;z-index:1;background:#f8fafc;text-align:left;color:#475467;font-size:12px;letter-spacing:.02em;text-transform:uppercase;border-bottom:1px solid var(--line);padding:12px}td{border-bottom:1px solid var(--line);padding:12px;vertical-align:top}tr.data-row{cursor:pointer}tr.data-row:hover{background:#f8fbff}.name-cell{font-weight:900;min-width:220px}.muted{color:var(--muted)}.detail-row td{background:#fbfdff;padding:0}.detail{display:grid;grid-template-columns:minmax(280px,.8fr) minmax(0,1.2fr);gap:18px;padding:18px}.breakdown{display:grid;gap:10px}.bar-row{display:grid;grid-template-columns:160px 1fr 52px;gap:10px;align-items:center}.bar{height:9px;border-radius:999px;background:#e5e7eb;overflow:hidden}.bar>span{display:block;height:100%;background:var(--blue);border-radius:999px}.detail-block{background:#fff;border:1px solid var(--line);border-radius:14px;padding:14px}.detail-block h4{margin:0 0 8px}.empty{padding:30px;text-align:center;color:var(--muted)}details.search-scope{padding:16px 18px}details.search-scope summary{cursor:pointer;font-weight:900}.scope-grid{display:grid;grid-template-columns:repeat(3,minmax(200px,1fr));gap:14px;margin-top:14px}.footer-note{margin-top:22px;color:var(--muted);font-size:12px;line-height:1.6}@media(max-width:1180px){.hero{grid-template-columns:1fr}.stats{grid-template-columns:repeat(3,1fr)}.top-grid{grid-template-columns:repeat(2,1fr)}.toolbar{grid-template-columns:1fr 1fr}.detail{grid-template-columns:1fr}}@media(max-width:720px){.page{padding:16px}.stats{grid-template-columns:1fr 1fr}.top-grid{grid-template-columns:1fr}.toolbar{grid-template-columns:1fr}.scope-grid{grid-template-columns:1fr}}
</style>
</head>
<body>
<div class="page">
<section class="hero"><div class="card hero-main"><div class="kicker">Channel Discovery</div><h1>__PRODUCT__ Channel Discovery Report</h1><div class="subtitle">A profile-driven channel board for outreach. Review fit score, source signals, contact paths, sponsorship signals, and suggested collaboration angles before contacting creators or media partners.</div></div><div class="card meta-list"><div class="meta-row"><span class="meta-label">Campaign</span><span class="meta-value">__CAMPAIGN__</span></div><div class="meta-row"><span class="meta-label">Run ID</span><span class="meta-value">__RUN_ID__</span></div><div class="meta-row"><span class="meta-label">Generated</span><span class="meta-value">__GENERATED__</span></div><div class="meta-row"><span class="meta-label">Source of truth</span><span class="meta-value">data/selected-50.json</span></div></div></section>
<section class="stats" id="stats"></section>
<section class="section card" id="warningSection"></section>
<section class="section card"><details class="search-scope"><summary>Search scope and run settings</summary><div class="scope-grid" id="scopeGrid"></div></details></section>
<section class="section"><div class="section-header"><div><div class="section-title">Top 10 Recommended Channels</div><div class="section-subtitle">Highest-fit candidates based on audience, content fit, activity, contactability, sponsor signals, reach, and search value.</div></div></div><div class="top-grid" id="topGrid"></div></section>
<section class="section card"><div class="section-header" style="padding:18px 18px 0"><div><div class="section-title">Candidate Channel Review Queue</div><div class="section-subtitle">Search, filter, sort, and click a row to expand score breakdown and next action.</div></div></div><div class="toolbar"><input id="searchInput" placeholder="Search name, topic, audience, notes..."/><select id="typeFilter"><option value="">All types</option></select><select id="priorityFilter"><option value="">All priorities</option><option>High</option><option>Medium</option><option>Low</option></select><select id="reviewFilter"><option value="">All review states</option><option>new</option><option>shortlisted</option><option>rejected</option><option>contacted</option><option>approved</option></select><select id="sortSelect"><option value="score_desc">Score high to low</option><option value="score_asc">Score low to high</option><option value="name_asc">Name A-Z</option></select><button id="resetBtn">Reset</button></div><div class="toggle-row"><label><input type="checkbox" id="contactOnly"/> Only with contact</label><label><input type="checkbox" id="sponsorOnly"/> Only with sponsor/media kit</label></div><div class="table-wrap"><table><thead><tr><th>Rank</th><th>Channel</th><th>Type</th><th>Topic</th><th>Reach</th><th>Score</th><th>Priority</th><th>Review</th><th>Source</th><th>Contact</th><th>Sponsor</th><th>Suggested Collaboration</th></tr></thead><tbody id="tableBody"></tbody></table></div></section>
<section class="section card" style="padding:18px"><div class="section-title">Scoring Standard</div><div class="chips" style="margin-top:12px"><span class="chip">Audience Match 30</span><span class="chip">Content Fit 20</span><span class="chip">Activity 15</span><span class="chip">Sponsorship Readiness 10</span><span class="chip">Contactability 10</span><span class="chip">Authority / Reach 10</span><span class="chip">Long-term Search Value 5</span></div><div class="footer-note">Missing values are shown as Unknown. This report does not infer private contact data, sponsorship pricing, audience composition, open rate, or undisclosed business email. Verify each candidate before outreach.</div></section>
</div>
<script>
const CHANNEL_DATA = __CHANNEL_DATA__;
const RUN_SUMMARY = __SUMMARY_DATA__;
const INPUT_CONFIG = __INPUT_DATA__;
const weights = {audience_match:30,content_fit:20,activity:15,sponsorship_readiness:10,contactability:10,authority_reach:10,long_term_search_value:5};
const labels = {audience_match:'Audience Match',content_fit:'Content Fit',activity:'Activity',sponsorship_readiness:'Sponsorship',contactability:'Contactability',authority_reach:'Authority / Reach',long_term_search_value:'Search Value'};
const state = {expanded:null};
function val(x){return x===undefined||x===null||x===''?'Unknown':x}
function hasKnown(x){return !(x===undefined||x===null||x===''||x==='Unknown')}
function esc(s){return String(val(s)).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}
function link(url,text){return hasKnown(url)?`<a href="${esc(url)}" target="_blank" rel="noopener">${esc(text||url)}</a>`:'Unknown'}
function renderStats(){const data=CHANNEL_DATA,total=data.length,high=data.filter(x=>x.priority==='High').length,medium=data.filter(x=>x.priority==='Medium').length,low=data.filter(x=>x.priority==='Low').length,avg=total?Math.round(data.reduce((s,x)=>s+(Number(x.fit_score)||0),0)/total):0,contact=data.filter(x=>hasKnown(x.contact_email)||hasKnown(x.contact_page)).length,sponsor=data.filter(x=>hasKnown(x.sponsor_page)||hasKnown(x.media_kit_url)).length,types=[...new Set(data.map(x=>x.channel_type||x.platform||'Unknown'))].slice(0,3).join(', ')||'Unknown';const stats=[['Total Candidates',total],['High Priority',high],['Medium Priority',medium],['Low Priority',low],['Avg Fit Score',avg],['Contact Available',contact],['Main Types',types]];document.getElementById('stats').innerHTML=stats.map(([label,value])=>`<div class="card stat"><div class="stat-value">${esc(value)}</div><div class="stat-label">${esc(label)}</div></div>`).join('')}
function renderWarnings(){const warnings=RUN_SUMMARY.warnings||[],statuses=RUN_SUMMARY.provider_statuses||[],el=document.getElementById('warningSection');if(!warnings.length&&!statuses.length){el.style.display='none';return}const warningHtml=warnings.map(w=>`<div class="warning-item">${esc(w)}</div>`).join(''),statusHtml=statuses.map(s=>{const cls=s.status==='ok'?'ok':(s.status==='failed'?'fail':'warn');const reason=s.skipped_reason||s.error||'';return `<span class="chip ${cls}">${esc(s.provider)}: ${esc(s.status)}${reason?' · '+esc(reason):''}${s.count?` · ${esc(s.count)}`:''}</span>`}).join('');el.innerHTML=`<div class="warning-list">${warningHtml||''}<div class="chips">${statusHtml}</div></div>`}
function renderScope(){const keywordHtml=(INPUT_CONFIG.keywords||[]).map(k=>`<span class="chip">${esc(k)}</span>`).join(''),typeHtml=(INPUT_CONFIG.channel_types||INPUT_CONFIG.target_channels||[]).map(k=>`<span class="chip">${esc(k)}</span>`).join(''),filters=[`Language: ${esc(INPUT_CONFIG.language||'English')}`,`Recent days: ${esc(INPUT_CONFIG.recent_days||'Unknown')}`,`Selected count: ${esc(INPUT_CONFIG.selected_count||50)}`,`Max raw candidates: ${esc(INPUT_CONFIG.max_raw_candidates||'Unknown')}`,'Deduplication: channel_id / canonical_url / domain / normalized_name'].map(x=>`<span class="chip">${x}</span>`).join('');document.getElementById('scopeGrid').innerHTML=`<div class="detail-block"><h4>Keywords</h4><div class="chips">${keywordHtml||'<span class="muted">Unknown</span>'}</div></div><div class="detail-block"><h4>Channel Types</h4><div class="chips">${typeHtml||'<span class="muted">Unknown</span>'}</div></div><div class="detail-block"><h4>Filters</h4><div class="chips">${filters}</div></div>`}
function renderTypeOptions(){const types=[...new Set(CHANNEL_DATA.map(x=>x.channel_type||x.platform||'Unknown'))].sort();document.getElementById('typeFilter').innerHTML='<option value="">All types</option>'+types.map(t=>`<option>${esc(t)}</option>`).join('')}
function renderTop(){const top=[...CHANNEL_DATA].sort((a,b)=>(Number(b.fit_score)||0)-(Number(a.fit_score)||0)).slice(0,10);document.getElementById('topGrid').innerHTML=top.map(c=>`<div class="card top-card"><div style="display:flex;justify-content:space-between;gap:8px;align-items:start"><h3>${link(c.url,c.name)}</h3><span class="score-pill">${esc(c.fit_score)}</span></div><div><span class="priority ${esc(c.priority)}">${esc(c.priority)}</span> <span class="small">${esc(c.platform)} · ${esc(c.channel_type)}</span></div><div class="small"><b>Why:</b> ${esc(c.score_reason)}</div><div class="small"><b>Collaboration:</b> ${esc(c.recommended_collaboration)}</div><div class="small"><b>Contact:</b> ${hasKnown(c.contact_email)?esc(c.contact_email):link(c.contact_page,'Contact page')}</div><div class="small"><b>Sponsor:</b> ${hasKnown(c.sponsor_page)?link(c.sponsor_page,'Sponsor page'):link(c.media_kit_url,'Media kit')}</div></div>`).join('')}
function getFiltered(){const q=document.getElementById('searchInput').value.toLowerCase(),type=document.getElementById('typeFilter').value,priority=document.getElementById('priorityFilter').value,review=document.getElementById('reviewFilter').value,contactOnly=document.getElementById('contactOnly').checked,sponsorOnly=document.getElementById('sponsorOnly').checked,sort=document.getElementById('sortSelect').value;let rows=CHANNEL_DATA.filter(c=>{const text=[c.name,c.topic,c.audience,c.score_reason,c.recommended_collaboration,c.notes,c.source_keyword,c.source_provider,c.source_url].join(' ').toLowerCase();if(q&&!text.includes(q))return false;if(type&&(c.channel_type||c.platform)!==type)return false;if(priority&&c.priority!==priority)return false;if(review&&(c.review_status||'new')!==review)return false;if(contactOnly&&!(hasKnown(c.contact_email)||hasKnown(c.contact_page)))return false;if(sponsorOnly&&!(hasKnown(c.sponsor_page)||hasKnown(c.media_kit_url)))return false;return true});if(sort==='score_asc')rows.sort((a,b)=>(Number(a.fit_score)||0)-(Number(b.fit_score)||0));else if(sort==='name_asc')rows.sort((a,b)=>String(a.name||'').localeCompare(String(b.name||'')));else rows.sort((a,b)=>(Number(b.fit_score)||0)-(Number(a.fit_score)||0));return rows}
function renderTable(){const rows=getFiltered(),body=document.getElementById('tableBody');if(!rows.length){body.innerHTML='<tr><td colspan="12"><div class="empty">No candidates match current filters.</div></td></tr>';return}body.innerHTML=rows.map((c,i)=>{const key=String(c.dedupe_key||c.rank||i);return `<tr class="data-row" onclick="toggleDetail('${esc(key)}')"><td>${esc(c.rank||i+1)}</td><td class="name-cell">${link(c.url,c.name)}<div class="small">${esc(c.platform)}</div></td><td>${esc(c.channel_type)}</td><td>${esc(c.topic)}</td><td><b>${esc(c.subscribers_or_followers)}</b><div class="small">Avg views: ${esc(c.avg_views)}</div></td><td><span class="score-pill">${esc(c.fit_score)}</span></td><td><span class="priority ${esc(c.priority)}">${esc(c.priority)}</span></td><td><span class="review">${esc(c.review_status||'new')}</span></td><td>${esc(c.source_provider||'Unknown')}<div class="small">${esc(c.confidence||'Unknown')}</div></td><td>${hasKnown(c.contact_email)?esc(c.contact_email):link(c.contact_page,'Contact page')}</td><td>${hasKnown(c.sponsor_page)?link(c.sponsor_page,'Sponsor'):link(c.media_kit_url,'Media kit')}</td><td>${esc(c.recommended_collaboration)}</td></tr>${state.expanded===key?detailRow(c):''}`}).join('')}
function detailRow(c){const breakdown=c.score_breakdown||{},bars=Object.keys(weights).map(key=>{const value=Number(breakdown[key]||0),max=weights[key],pct=Math.max(0,Math.min(100,(value/max)*100));return `<div class="bar-row"><div class="small">${labels[key]}</div><div class="bar"><span style="width:${pct}%"></span></div><div class="small">${value}/${max}</div></div>`}).join(''),missing=(c.missing_fields||[]).length?c.missing_fields.map(x=>`<span class="chip">${esc(x)}</span>`).join(''):'<span class="chip">None</span>';return `<tr class="detail-row"><td colspan="12"><div class="detail"><div class="detail-block"><h4>Score Breakdown</h4><div class="breakdown">${bars}</div></div><div class="detail-block"><h4>Channel Details</h4><p><b>Reason:</b> ${esc(c.score_reason)}</p><p><b>Suggested next action:</b> ${esc(c.recommended_collaboration)}</p><p><b>Review:</b> ${esc(c.review_status||'new')} ${c.review_notes?'- '+esc(c.review_notes):''}</p><p><b>Source:</b> ${esc(c.source_provider||'Unknown')} · ${link(c.source_url,'source')}</p><p><b>Recent activity:</b> ${esc(c.recent_activity)}</p><p><b>Contact:</b> ${hasKnown(c.contact_email)?esc(c.contact_email):link(c.contact_page,'Contact page')}</p><p><b>Sponsor:</b> ${hasKnown(c.sponsor_page)?link(c.sponsor_page,'Sponsor page'):link(c.media_kit_url,'Media kit')}</p><p><b>Missing information:</b></p><div class="chips">${missing}</div><p class="small"><b>Notes:</b> ${esc(c.notes||'Unknown')}</p></div></div></td></tr>`}
function toggleDetail(key){state.expanded=state.expanded===String(key)?null:String(key);renderTable()}
['searchInput','typeFilter','priorityFilter','reviewFilter','sortSelect','contactOnly','sponsorOnly'].forEach(id=>document.getElementById(id).addEventListener('input',renderTable));document.getElementById('resetBtn').addEventListener('click',()=>{document.getElementById('searchInput').value='';document.getElementById('typeFilter').value='';document.getElementById('priorityFilter').value='';document.getElementById('reviewFilter').value='';document.getElementById('sortSelect').value='score_desc';document.getElementById('contactOnly').checked=false;document.getElementById('sponsorOnly').checked=false;state.expanded=null;renderTable()});
renderStats();renderWarnings();renderScope();renderTypeOptions();renderTop();renderTable();
</script>
</body>
</html>'''
    html_doc = (
        template
        .replace("__PRODUCT__", html.escape(str(input_config.get("product_name") or "Product")))
        .replace("__CAMPAIGN__", html.escape(campaign_slug))
        .replace("__RUN_ID__", html.escape(run_id))
        .replace("__GENERATED__", html.escape(generated_at))
        .replace("__CHANNEL_DATA__", json.dumps(candidates, ensure_ascii=False).replace("</", "<\\/"))
        .replace("__SUMMARY_DATA__", json.dumps(summary, ensure_ascii=False).replace("</", "<\\/"))
        .replace("__INPUT_DATA__", json.dumps(input_config, ensure_ascii=False).replace("</", "<\\/"))
    )
    path.write_text(html_doc, encoding="utf-8")
